mapper.select:
SELECT id, driver_id, vehicle_id, status, planned_date
FROM routes
WHERE id = #{id}

mapper.update:
UPDATE routes
SET driver_id = #{driverId, jdbcType=OTHER},
    vehicle_id = #{vehicleId, jdbcType=OTHER},
    status = #{status},
    planned_date = #{plannedDate}
WHERE id = #{id, jdbcType=OTHER}
